import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void creditsAndDebits() {
        int[] result = new Solution().findMatchingTransactions(new int[]{-100, 250, 150, -50}, 200);
        assertArrayEquals(new int[]{1, 3}, result);
    }

    @Test
    void simpleCreditPair() {
        int[] result = new Solution().findMatchingTransactions(new int[]{100, 200, 300}, 500);
        assertArrayEquals(new int[]{1, 2}, result);
    }

    @Test
    void earliestCompleter() {
        // Iteration: j=0 (5) miss, j=1 (3) miss, j=2 (1) miss, j=3 (5) finds 5 at i=0.
        // Returns {0, 3} — the first j where a pair completes.
        int[] result = new Solution().findMatchingTransactions(new int[]{5, 3, 1, 5}, 10);
        assertArrayEquals(new int[]{0, 3}, result);
    }

    @Test
    void zeroTarget() {
        int[] result = new Solution().findMatchingTransactions(new int[]{-42, 17, 42}, 0);
        assertArrayEquals(new int[]{0, 2}, result);
    }
}
